import type { Metadata } from "next";
import Link from "next/link";
import { notFound } from "next/navigation";

import Prose from "@/components/prose";
import { readImportedPage } from "@/lib/local-content";
import { getPageBySlug } from "@/lib/wp";

export const metadata: Metadata = {
    title: "About",
};

export default async function AboutPage() {
    // Try to get from WordPress first, then fallback to local
    let wpPage = null;
    let page = null;

    try {
        wpPage = await getPageBySlug("about-us");
    } catch {
        // Fallback to local content
    }

    if (!wpPage) {
        page = readImportedPage("about-us");
    }

    const content = wpPage || page;

    if (!content) notFound();

    return (
        <div className="mx-auto flex w-full max-w-4xl flex-col gap-8">
            <div className="flex flex-wrap items-center justify-between gap-3">
                <Link href="/" className="text-sm font-semibold text-accent hover:opacity-90">
                    ← Back home
                </Link>
            </div>

            <section className="card animate-fe-fade-up overflow-hidden rounded-[28px] p-6 md:p-8">
                <p className="text-sm font-semibold text-accent">About</p>
                <h1 className="mt-2 text-3xl font-semibold tracking-tight md:text-4xl">
                    {wpPage ? wpPage.title.rendered.replace(/<[^>]*>/g, "") : (page?.title || "About Us")}
                </h1>
            </section>

            <div className="card animate-fe-fade-up overflow-hidden rounded-[28px] p-6 md:p-8">
                <Prose>
                    <div dangerouslySetInnerHTML={{
                        __html: wpPage ? wpPage.content.rendered : page?.html || ""
                    }} />
                </Prose>
            </div>
        </div>
    );
}
