import type { ReactNode } from "react";

export default function Prose({ children }: { children: ReactNode }) {
    return (
        <div className="prose prose-lg max-w-none">
            <style jsx>{`
                .prose h1 {
                    @apply text-3xl font-bold text-foreground mt-8 mb-4;
                }
                .prose h2 {
                    @apply text-2xl font-semibold text-foreground mt-6 mb-3;
                }
                .prose h3 {
                    @apply text-xl font-semibold text-foreground mt-4 mb-2;
                }
                .prose p {
                    @apply text-foreground leading-relaxed mb-4;
                }
                .prose ul, .prose ol {
                    @apply text-foreground mb-4 pl-6;
                }
                .prose li {
                    @apply mb-2;
                }
                .prose a {
                    @apply text-accent hover:text-accent/80 underline;
                }
                .prose strong {
                    @apply font-semibold text-foreground;
                }
                .prose blockquote {
                    @apply border-l-4 border-accent pl-4 italic text-muted;
                }
                .prose img {
                    @apply rounded-lg my-6;
                }
                .prose code {
                    @apply bg-secondary px-2 py-1 rounded text-sm font-mono;
                }
                .prose pre {
                    @apply bg-secondary p-4 rounded-lg overflow-x-auto my-4;
                }
                .prose table {
                    @apply w-full border-collapse my-4;
                }
                .prose th, .prose td {
                    @apply border border-border p-2 text-left;
                }
                .prose th {
                    @apply bg-secondary font-semibold;
                }
            `}</style>
            {children}
        </div>
    );
}
