import { WP_API_BASE } from "@/lib/config";
import type { WPCategory, WPPage, WPPost } from "@/lib/wp-types";

type FetchJsonInit = Omit<RequestInit, "headers"> & {
  headers?: Record<string, string>;
};

function buildUrl(path: string, query?: Record<string, string | number | boolean | undefined>) {
  const url = new URL(path.replace(/^\//, ""), WP_API_BASE.endsWith("/") ? WP_API_BASE : `${WP_API_BASE}/`);
  if (query) {
    for (const [k, v] of Object.entries(query)) {
      if (v === undefined) continue;
      url.searchParams.set(k, String(v));
    }
  }
  return url.toString();
}

async function fetchJson<T>(path: string, query?: Record<string, string | number | boolean | undefined>, init?: FetchJsonInit) {
  const url = buildUrl(path, query);
  const res = await fetch(url, {
    ...init,
    headers: {
      Accept: "application/json",
      ...(init?.headers ?? {}),
    },
    next: {
      revalidate: 60,
    },
  });

  if (!res.ok) {
    const text = await res.text().catch(() => "");
    throw new Error(`WP request failed (${res.status}) ${url}${text ? `\n${text}` : ""}`);
  }

  return (await res.json()) as T;
}

export async function getCategories(perPage = 50) {
  return fetchJson<WPCategory[]>("/categories", {
    per_page: perPage,
    hide_empty: true,
    orderby: "count",
    order: "desc",
  });
}

export async function getLatestPosts(perPage = 12) {
  return fetchJson<WPPost[]>("/posts", {
    per_page: perPage,
    _embed: true,
  });
}

export async function getPostsByCategorySlug(slug: string, perPage = 12) {
  const cats = await fetchJson<WPCategory[]>("/categories", { slug, per_page: 1 });
  const cat = cats[0];
  if (!cat) return { category: null as WPCategory | null, posts: [] as WPPost[] };

  const posts = await fetchJson<WPPost[]>("/posts", {
    categories: cat.id,
    per_page: perPage,
    _embed: true,
  });

  return { category: cat, posts };
}

export async function getPostBySlug(slug: string) {
  const posts = await fetchJson<WPPost[]>("/posts", { slug, per_page: 1, _embed: true });
  return posts[0] ?? null;
}

export async function getPageBySlug(slug: string) {
  const pages = await fetchJson<WPPage[]>("/pages", { slug, per_page: 1, _embed: true });
  return pages[0] ?? null;
}
